import React, {useState} from 'react'
import ReactPlayer from "react-player";
import ScrollAnimation from "react-animate-on-scroll";
import {fadeIn, fadeOut} from "react-animations";
import styled, { keyframes } from 'styled-components';
const Projects = () => {
    const [isShown, SetIsShown] = useState("");
    const [isPlayable,SetPlayable] = useState(0);
    const FadeIn = styled.div`animation: 0.5s ${keyframes`${fadeIn}`} 1 `;
    const FadeOut = styled.div`animation: 0.5s ${keyframes`${fadeOut}`} 1 `;
    return(
        <div className="ui center aligned segment">
            <div className="grid">
                <div className="cell"
                     onMouseEnter={() => (SetIsShown("demo1"),SetPlayable(1))}
                     onMouseLeave={() => (SetIsShown(""),SetPlayable(0))}
                >
                    <ReactPlayer
                        url="./videos/Helicopter_Demo.MP4"
                        width='40vw'
                        height='40vh'
                        controls={isPlayable ? 0 : 1}
                        style={{opacity:isShown ? "":"demo1",transition: "opacity 1s"}}
                    ></ReactPlayer>
                </div>
                <div className="cell"
                     onMouseEnter={() => (SetIsShown("demo2"),SetPlayable(2))}
                     onMouseLeave={() => (SetIsShown(""),SetPlayable(0))}
                >
                    <ReactPlayer
                        url="./videos/Solar_System_Demo.MP4"
                        width='40vw'
                        height='40vh'
                        controls={isPlayable ? 0 : 2}
                        style={{opacity:isShown ? "":"demo2",transition: "opacity 1s"}}
                    ></ReactPlayer>
                </div>
            </div>
        </div>
    );
};
export default Projects;
